+function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Ornate gold throne with red cushion, 28x32 px approx, detailed pixel art
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Backrest frame with carved details
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(4, 0, 20, 28);
+  ctx.strokeStyle = '#a67c00';
+  ctx.lineWidth = 1;
+  // Carving lines
+  for (let i = 5; i < 24; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 2);
+    ctx.lineTo(i - 2, 10);
+    ctx.stroke();
+  }
+  // Cushion (red velvet with shading)
+  ctx.fillStyle = '#a32a2a';
+  ctx.fillRect(6, 18, 16, 10);
+  ctx.fillStyle = '#7a1a1a';
+  ctx.fillRect(6, 23, 16, 5);
+  // Decorative top arch with gradient fill
+  const grad = ctx.createLinearGradient(4, 0, 24, 0);
+  grad.addColorStop(0, '#d4af37');
+  grad.addColorStop(0.5, '#f0d75e');
+  grad.addColorStop(1, '#d4af37');
+  ctx.fillStyle = grad;
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -12, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+  // Legs with shadows and highlights
+  ctx.fillStyle = '#bfa03e';
+  ctx.fillRect(4, 28, 6, 4);
+  ctx.fillRect(18, 28, 6, 4);
+  ctx.strokeStyle = '#8a6f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(4, 28, 6, 4);
+  ctx.strokeRect(18, 28, 6, 4);
+  ctx.restore();
+}
+
+function drawPlanningTable(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Wood table with detailed map scroll, 30x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Table top (brown wood with grain)
+  ctx.fillStyle = '#6b4c2b';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#5a3f21';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 28; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 2, 18);
+    ctx.stroke();
+  }
+  // Table legs with shading
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(2, 20, 4, 6);
+  ctx.fillRect(24, 20, 4, 6);
+  // Map scroll (light parchment with rolled edges)
+  ctx.fillStyle = '#d9cba3';
+  ctx.beginPath();
+  ctx.moveTo(6, 10);
+  ctx.lineTo(24, 10);
+  ctx.quadraticCurveTo(26, 12, 24, 18);
+  ctx.lineTo(6, 18);
+  ctx.quadraticCurveTo(4, 16, 6, 10);
+  ctx.fill();
+  ctx.strokeStyle = '#b8a97a';
+  ctx.lineWidth = 1;
+  ctx.stroke();
+  // Map details (green lines with dots)
+  ctx.strokeStyle = '#3a6b35';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(8, 12);
+  ctx.lineTo(22, 14);
+  ctx.moveTo(10, 16);
+  ctx.lineTo(20, 18);
+  ctx.stroke();
+  // Dots on map
+  ctx.fillStyle = '#2a4b25';
+  ctx.beginPath();
+  ctx.arc(12, 13, 1.5, 0, Math.PI * 2);
+  ctx.arc(18, 16, 1.5, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawWeaponRack(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Weapon rack with detailed sword silhouettes, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Rack frame (dark wood with grain)
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  ctx.strokeStyle = '#3a2510';
+  ctx.lineWidth = 1;
+  for (let i = 4; i < 26; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 5);
+    ctx.lineTo(i, 22);
+    ctx.stroke();
+  }
+  // Crossbars with nails
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  ctx.fillStyle = '#3a2510';
+  for (let i = 4; i < 26; i += 6) {
+    ctx.beginPath();
+    ctx.arc(i, 9, 1, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.arc(i, 17, 1, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  // Swords (gray blades with hilts)
+  ctx.strokeStyle = '#a0a0a0';
+  ctx.lineWidth = 2;
+  // Sword 1 blade
+  ctx.beginPath();
+  ctx.moveTo(8, 7);
+  ctx.lineTo(8, 21);
+  ctx.stroke();
+  // Sword 1 hilt
+  ctx.fillStyle = '#5a5a5a';
+  ctx.fillRect(5, 6, 6, 2);
+  ctx.fillRect(7, 21, 2, 3);
+  // Sword 2 blade
+  ctx.beginPath();
+  ctx.moveTo(16, 7);
+  ctx.lineTo(16, 21);
+  ctx.stroke();
+  // Sword 2 hilt
+  ctx.fillStyle = '#5a5a5a';
+  ctx.fillRect(13, 6, 6, 2);
+  ctx.fillRect(15, 21, 2, 3);
+  ctx.restore();
+}
+
+function drawWorkbench(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Workbench with detailed tools, 32x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Bench top (medium brown with wood grain)
+  ctx.fillStyle = '#7a5230';
+  ctx.fillRect(0, 8, 32, 12);
+  ctx.strokeStyle = '#6a4320';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 30; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Legs with shading
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(24, 20, 6, 4);
+  ctx.strokeStyle = '#4a2f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(24, 20, 6, 4);
+  // Hammer (handle + head) with highlights
+  ctx.strokeStyle = '#3a2f2a';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(8, 14);
+  ctx.lineTo(8, 18);
+  ctx.moveTo(6, 18);
+  ctx.lineTo(10, 18);
+  ctx.stroke();
+  ctx.fillStyle = '#5a4a40';
+  ctx.fillRect(5, 13, 6, 2);
+  // Saw blade (gray jagged with teeth)
+  ctx.fillStyle = '#a0a0a0';
+  ctx.beginPath();
+  ctx.moveTo(20, 14);
+  for (let i = 0; i < 5; i++) {
+    ctx.lineTo(20 + i * 2, 14 + (i % 2 === 0 ? 4 : 0));
+  }
+  ctx.lineTo(30, 18);
+  ctx.closePath();
+  ctx.fill();
+  // Saw teeth highlights
+  ctx.strokeStyle = '#7a7a7a';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  for (let i = 0; i < 5; i++) {
+    ctx.moveTo(20 + i * 2, 14);
+    ctx.lineTo(20 + i * 2, 18);
+  }
+  ctx.stroke();
+  ctx.restore();
+}
+
+function drawPotionShelf(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Shelf with detailed colored bottles, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Shelf frame (dark wood with grain)
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  ctx.strokeStyle = '#3a2510';
+  ctx.lineWidth = 1;
+  for (let i = 4; i < 26; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 5);
+    ctx.lineTo(i, 22);
+    ctx.stroke();
+  }
+  // Shelf boards with nails
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  ctx.fillStyle = '#3a2510';
+  for (let i = 4; i < 26; i += 6) {
+    ctx.beginPath();
+    ctx.arc(i, 9, 1, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.arc(i, 17, 1, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  // Bottles (red, blue, green) with highlights and shadows
+  const bottleColors = ['#c33', '#339', '#393'];
+  for (let i = 0; i < 3; i++) {
+    const cx = 8 + i * 8;
+    ctx.fillStyle = bottleColors[i];
+    // Bottle body
+    ctx.beginPath();
+    ctx.ellipse(cx, 14, 4, 6, 0, 0, Math.PI * 2);
+    ctx.fill();
+    // Bottle highlight
+    const grad = ctx.createRadialGradient(cx - 2, 12, 1, cx, 14, 5);
+    grad.addColorStop(0, 'rgba(255,255,255,0.5)');
+    grad.addColorStop(1, 'rgba(255,255,255,0)');
+    ctx.fillStyle = grad;
+    ctx.beginPath();
+    ctx.ellipse(cx - 1, 12, 2, 4, 0, 0, Math.PI * 2);
+    ctx.fill();
+    // Bottle shadow
+    ctx.fillStyle = 'rgba(0,0,0,0.2)';
+    ctx.beginPath();
+    ctx.ellipse(cx + 1, 16, 2, 4, 0, 0, Math.PI * 2);
+    ctx.fill();
+    // Bottle outline
+    ctx.strokeStyle = '#222';
+    ctx.lineWidth = 1;
+    ctx.beginPath();
+    ctx.ellipse(cx, 14, 4, 6, 0, 0, Math.PI * 2);
+    ctx.stroke();
+    // Bottle neck
+    ctx.fillStyle = bottleColors[i];
+    ctx.fillRect(cx - 1, 7, 2, 4);
+    ctx.strokeRect(cx - 1, 7, 2, 4);
+  }
+  ctx.restore();
+}
+
+function drawScribeDesk(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Desk with quill and book, 30x24 px approx, detailed pixel art
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Desk top (dark wood with grain)
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#4a2f10';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 28; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Legs
+  ctx.fillStyle = '#4a2f10';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(22, 20, 6, 4);
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(22, 20, 6, 4);
+  // Open book (cream pages with lines)
+  ctx.fillStyle = '#f9f4d7';
+  ctx.fillRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#d9d1a3';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#a3a375';
+  for (let y = 12; y < 17; y += 2) {
+    ctx.beginPath();
+    ctx.moveTo(7, y);
+    ctx.lineTo(23, y);
+    ctx.stroke();
+  }
+  // Quill (white feather with black tip)
+  ctx.strokeStyle = '#222';
+  ctx.lineWidth = 1;
+  ctx.fillStyle = '#eee';
+  ctx.beginPath();
+  ctx.moveTo(24, 12);
+  ctx.lineTo(28, 8);
+  ctx.lineTo(26, 6);
+  ctx.lineTo(22, 10);
+  ctx.closePath();
+  ctx.fill();
+  ctx.stroke();
+  ctx.fillStyle = '#111';
+  ctx.beginPath();
+  ctx.moveTo(26, 6);
+  ctx.lineTo(27, 5);
+  ctx.lineTo(28, 6);
+  ctx.lineTo(26, 6);
+  ctx.fill();
+  // Ink pot (black with shine)
+  ctx.fillStyle = '#111';
+  ctx.beginPath();
+  ctx.ellipse(20, 20, 4, 3, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.strokeStyle = '#444';
+  ctx.stroke();
+  ctx.fillStyle = '#555';
+  ctx.beginPath();
+  ctx.ellipse(18, 19, 1, 0.5, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawHealingBasin(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Healing basin with water and herbs, 28x28 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+  // Basin bowl (ceramic, light blue)
+  ctx.fillStyle = '#a3c9e0';
+  ctx.beginPath();
+  ctx.ellipse(14, 16, 12, 8, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.strokeStyle = '#6a9acb';
+  ctx.lineWidth = 1;
+  ctx.stroke();
+  // Water surface (wavy lines)
+  ctx.strokeStyle = '#4a7abf';
+  ctx.lineWidth = 1;
+  for (let yline = 12; yline <= 20; yline += 3) {
+    ctx.beginPath();
+    for (let xline = 2; xline <= 26; xline += 4) {
+      ctx.lineTo(xline, yline + (xline % 8 === 0 ? 1 : -1));
+    }
+    ctx.stroke();
+  }
+  // Herbs floating (green leaves)
+  ctx.fillStyle = '#3a6b35';
+  ctx.beginPath();
+  ctx.ellipse(10, 14, 3, 1.5, Math.PI / 6, 0, Math.PI * 2);
+  ctx.ellipse(18, 18, 4, 2, -Math.PI / 8, 0, Math.PI * 2);
+  ctx.fill();
+  // Basin base
+  ctx.fillStyle = '#7a9acb';
+  ctx.fillRect(6, 22, 16, 4);
+  ctx.strokeStyle = '#4a6a9b';
+  ctx.strokeRect(6, 22, 16, 4);
+  ctx.restore();
+}
+
+// Export drawFurniture with new pieces included
+export function drawFurniture(ctx: CanvasRenderingContext2D, type: string, x: number, y: number, size: number) {
+  switch (type) {
+    case 'throne':
+      drawThrone(ctx, x, y, size / 28);
+      break;
+    case 'planningTable':
+      drawPlanningTable(ctx, x, y, size / 30);
+      break;
+    case 'weaponRack':
+      drawWeaponRack(ctx, x, y, size / 28);
+      break;
+    case 'workbench':
+      drawWorkbench(ctx, x, y, size / 32);
+      break;
+    case 'potionShelf':
+      drawPotionShelf(ctx, x, y, size / 28);
+      break;
+    case 'scribeDesk':
+      drawScribeDesk(ctx, x, y, size / 30);
+      break;
+    case 'healingBasin':
+      drawHealingBasin(ctx, x, y, size / 28);
+      break;
+    default:
+      // fallback: simple rectangle
+      ctx.fillStyle = '#888';
+      ctx.fillRect(x, y, size, size);
+      break;
+  }
+}
+
